from concurrent.futures import ThreadPoolExecutor  # noqa: PLC0415

origs = [s.strip() for s in sentences]
news = [s.strip() for s in new_sentences]
# Decide, WITHOUT any I/O, which sentences actually changed AND keep an identical provenance-token
# multiset (TOKEN GUARD) — only those need a base-bar re-verify. Every other sentence resolves to
# its original inline, so the judge is called exactly once per diffed sentence.
changed_idx = [
    i
    for i, (o, n) in enumerate(zip(origs, news))
    if n and n != o and _ev_token_multiset(n) == _ev_token_multiset(o)
]

def _reverify_changed() -> dict:
    # BLOCKING: verify_sentence_provenance -> context NLI entailment + forward numeric match waits
    # on the judge (fut.result, ~5-9s). Called inline per sentence it froze the whole compose event
    # loop for N_sentences x that. The ENTIRE sweep runs here in ONE off-loop hop; a bounded pool
    # fans the changed sentences out (judge POSTs stay capped by PG_SIDE_JUDGE_MAX_CONCURRENCY).
    results: dict = {}
    if not changed_idx:
        return results
    workers = max(1, min(_env_int(_COHERENCE_VERIFY_WORKERS_ENV, _DEFAULT_COHERENCE_VERIFY_WORKERS), len(changed_idx)))

    def _verify_one(i: int):
        try:
            return verify_sentence_provenance(news[i], evidence_pool)
        except Exception:  # noqa: BLE001 — verifier fault on this sentence => keep original
            return None

    with ThreadPoolExecutor(max_workers=workers, thread_name_prefix="coh-verify") as pool:
        for i, res in zip(changed_idx, pool.map(_verify_one, changed_idx)):
            results[i] = res
    return results

verify_results = await asyncio.to_thread(_reverify_changed)

out: list[str] = []
changed = 0
for i, (orig, new) in enumerate(zip(origs, news)):
    if i not in verify_results:
        # unchanged / empty / token-guard failure — keep the original, no judge call was made
        out.append(orig)
        continue
    res = verify_results[i]
    # BASE-BAR RE-VERIFY verdict: fail (or verifier fault -> None) => keep original.
    if res is not None and bool(getattr(res, "is_verified", False)):
        out.append(str(getattr(res, "sentence", "") or new).strip() or orig)
        changed += 1
    else:
        out.append(orig)
if changed:
    logger.info("[section_polish] coherence rewrite resolved referents in %d sentence(s)", changed)
return " ".join(s for s in out if s)
